// toggleIDScript returns the JS expression for adding/removing an invoice ID from the selectedIds signal.
func toggleIDScript(id string) string {
	return fmt.Sprintf(
		"const _a=$selectedIds.split(',').filter(x=>x!='');const _i=_a.indexOf('%s');if($el.checked){if(_i<0)_a.push('%s')}else{if(_i>=0)_a.splice(_i,1)};$selectedIds=_a.join(',')",
		id, id,
	)
}

